  .comparison-table td {
    padding: 22px 24px;
    font-size: 20px;
    font-weight: 500;
    background: var(--bg-card);
    border-bottom: 1px solid var(--border);
  }

  .comparison-table tr:last-child td {
    border-bottom: none;
  }
  .os-icon {
    display: inline-block;
    width: 36px;
    height: 36px;
    border-radius: 8px;
    text-align: center;
    line-height: 36px;
    font-size: 18px;
    margin-right: 12px;
    vertical-align: middle;
  }

  /* ── Bar chart ── */
  .bar-chart {
    display: flex;
    flex-direction: column;
    gap: 20px;
    margin: 24px 0;
  }

  .bar-row {
    display: flex;
    align-items: center;
    gap: 16px;
  }

  .bar-label {
    width: 120px;
    font-size: 18px;
    font-weight: 600;
    text-align: right;
    flex-shrink: 0;
  }

  .bar-track {
    flex: 1;
    height: 48px;
    background: var(--bg-card);
    border-radius: 12px;
    overflow: hidden;
    position: relative;
  }

  .bar-fill {
    height: 100%;
    border-radius: 12px;
    display: flex;
    align-items: center;
    padding-left: 16px;
    font-size: 18px;
    font-weight: 700;
    color: white;
    min-width: 80px;
  }

  /* ── Stat boxes ── */
  .stat-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 20px;
    margin: 24px 0;
  }

  .stat-box {
    background: var(--bg-card);
    border: 1px solid var(--border);
    border-radius: 16px;
    padding: 28px;
    text-align: center;
  }

  .stat-value {
    font-size: 48px;
    font-weight: 800;
    margin-bottom: 8px;
  }

  .stat-label {
    font-size: 16px;
    font-weight: 500;
    color: var(--text-secondary);
  }

  /* ── Flow / Steps ── */
  .step-list {
    display: flex;
    flex-direction: column;
    gap: 16px;
  }

  .step-item {
    display: flex;
    align-items: flex-start;
    gap: 20px;
    background: var(--bg-card);
    border: 1px solid var(--border);
    border-radius: 16px;
    padding: 24px;
  }

  .step-num {
    width: 44px;
    height: 44px;
    border-radius: 12px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 20px;
    font-weight: 800;
    flex-shrink: 0;
  }

  .step-content h3 {
    font-size: 20px;
    font-weight: 700;
    margin-bottom: 6px;
